function randomKey() {
  return Math.random().toString(36).slice(2, 10);
}

function slugify(input) {
  return String(input || '')
    .toLowerCase()
    .trim()
    .replace(/["']/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 120);
}

function buildUniqueSlug(baseInput) {
  const baseSlug = slugify(baseInput) || 'article';
  const uniqueSuffix = Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
  const maxBaseLength = Math.max(1, 120 - uniqueSuffix.length - 1);
  const trimmedBase = baseSlug.slice(0, maxBaseLength).replace(/-+$/g, '') || 'article';
  return trimmedBase + '-' + uniqueSuffix;
}

function stripCodeFences(text) {
  const trimmed = String(text || '').trim();
  const tick = String.fromCharCode(96);
  const fence = tick + tick + tick;
  if (!trimmed.startsWith(fence)) return trimmed;

  const firstNl = trimmed.indexOf('\n');
  let content = firstNl >= 0 ? trimmed.slice(firstNl + 1) : trimmed.slice(fence.length);
  if (content.endsWith(fence)) content = content.slice(0, -fence.length);
  return content.trim();
}

function extractResponseText(resp) {
  if (typeof resp.output_text === 'string' && resp.output_text.trim()) return resp.output_text;

  if (Array.isArray(resp.output)) {
    for (const item of resp.output) {
      if (!Array.isArray(item.content)) continue;
      for (const content of item.content) {
        if (typeof content?.text === 'string' && content.text.trim()) return content.text;
      }
    }
  }

  if (Array.isArray(resp.choices) && typeof resp.choices[0]?.message?.content === 'string') {
    return resp.choices[0].message.content;
  }

  throw new Error('Unable to extract text from OpenAI response');
}

function makeBlock(style, text) {
  return {
    _key: randomKey(),
    _type: 'block',
    style,
    markDefs: [],
    children: [{ _key: randomKey(), _type: 'span', marks: [], text }],
  };
}

function markdownToPortableText(markdown) {
  const lines = String(markdown || '').split(/\r?\n/);
  const blocks = [];
  let paragraph = [];

  const pushParagraph = () => {
    const text = paragraph.join(' ').trim();
    if (!text) return;
    blocks.push(makeBlock('normal', text));
    paragraph = [];
  };

  for (const rawLine of lines) {
    const line = rawLine.trim();

    if (!line) {
      pushParagraph();
      continue;
    }

    if (line.startsWith('### ')) {
      pushParagraph();
      blocks.push(makeBlock('h3', line.replace(/^###\s+/, '')));
      continue;
    }

    if (line.startsWith('## ')) {
      pushParagraph();
      blocks.push(makeBlock('h2', line.replace(/^##\s+/, '')));
      continue;
    }

    if (line.startsWith('# ')) {
      pushParagraph();
      blocks.push(makeBlock('h2', line.replace(/^#\s+/, '')));
      continue;
    }

    if (line.startsWith('- ') || line.startsWith('* ')) {
      pushParagraph();
      blocks.push(makeBlock('normal', line.replace(/^[-*]\s+/, '')));
      continue;
    }

    paragraph.push(line);
  }

  pushParagraph();
  return blocks;
}

function resolveCategorySlug(ctx) {
  const classifier = [
    ctx.title,
    ctx.excerpt,
    ctx.query,
    ctx.targetKeyword,
    ctx.brief && ctx.brief.angle,
    ctx.brief && ctx.brief.outlineMarkdown,
  ].filter(Boolean).join(' ').toLowerCase();

  if (/(garden|gardening|patio|yard|lawn|outdoor|plant|raised bed|balcony|seedling|mulch|compost)/.test(classifier)) {
    return 'garden-basics';
  }
  if (/(clean|cleaning|laundry|bathroom|kitchen|maintenance|reset|vacuum|mop|stain|sanitize|disinfect)/.test(classifier)) {
    return 'cleaning-maintenance';
  }
  return 'home-organization';
}

function scopedCategoryId(siteSlug, categorySlug) {
  const safeSiteSlug = String(siteSlug || '').toLowerCase().trim().replace(/[^a-z0-9-]+/g, '-').replace(/^-+|-+$/g, '');
  if (!safeSiteSlug) throw new Error('Missing/invalid siteSlug for category reference');
  const safeCategorySlug = String(categorySlug || 'home-organization').toLowerCase().trim().replace(/[^a-z0-9-]+/g, '-').replace(/^-+|-+$/g, '') || 'home-organization';
  return 'category-' + safeSiteSlug + '-' + safeCategorySlug;
}

const topic = $('Explode Topics').item.json;
const siteSlug = String(topic.siteSlug || $env.SITE_SLUG || '').toLowerCase().trim();
if (!siteSlug) throw new Error('Missing siteSlug in article normalization');
const rawText = extractResponseText($json);
const parsed = JSON.parse(stripCodeFences(rawText));

const title = parsed.title || topic.query || 'Untitled article';
const slug = buildUniqueSlug(parsed.slug || title);
const excerpt = String(parsed.excerpt || '').trim().slice(0, 320);
const body = Array.isArray(parsed.body) ? parsed.body : markdownToPortableText(parsed.bodyMarkdown || parsed.content || '');
const faqItems = Array.isArray(parsed.faqItems)
  ? parsed.faqItems
      .filter((x) => x && x.question && x.answer)
      .slice(0, 5)
      .map((x) => ({
        _key: randomKey(),
        _type: 'faqItem',
        question: String(x.question).trim(),
        answer: String(x.answer).trim(),
      }))
  : [];

const seoTitle = String(parsed.seoTitle || title).slice(0, 70);
const seoDescription = String(parsed.seoDescription || excerpt).slice(0, 170);

const wordCount = body
  .flatMap((b) => (Array.isArray(b.children) ? b.children : []))
  .map((c) => c.text || '')
  .join(' ')
  .split(/\s+/)
  .filter(Boolean).length;

const normalizedCategorySlug = String(topic.categorySlug || '').trim().toLowerCase();
const categoryRef = scopedCategoryId(
  siteSlug,
  normalizedCategorySlug || resolveCategorySlug({
    title,
    excerpt,
    query: topic.query,
    targetKeyword: topic.targetKeyword,
    brief: topic.brief,
  })
);

return {
  json: {
      ...topic,
      siteSlug,
      title,
      slug,
      excerpt: excerpt || ('Practical ' + (topic.targetKeyword || 'home and DIY') + ' tips for beginners.'),
      body,
      faqItems,
      seoTitle,
      seoDescription,
      disclaimerVariant: parsed.disclaimerVariant === 'safety' ? 'safety' : 'general',
      wordCount,
      readTimeMinutes: Math.max(1, Math.round(wordCount / 220)),
      categoryRef,
    },
};

